import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { environment } from 'src/environments/environment';

import { Gener } from '../interfaces/gener';
import { Movie } from '../interfaces/movie';


@Injectable({
  providedIn: 'root'
})
export class HttpRequestsService 
{
  private getMovieGenerListURL= 'genre/movie/list';
  private getMoviesByGenerURL ='genre/';
  private getMovieDetailsByMovieIdURL = 'movie/';

  constructor(private httpClient: HttpClient) { }

  getMoviegenerList()
  {
    return this.httpClient.get<{ genres: Gener[] }>
    (environment.baseURL+this.getMovieGenerListURL,
      {
        params: { 'api_key': environment.apiToken }
      }
    );
  }

  getMoviesByGener(generId: number)
  {
    return this.httpClient.get<{ id: number, page: number, results: Movie[] }>
    (environment.baseURL+this.getMoviesByGenerURL+generId+'/movies',
      {
        params: { 'api_key': environment.apiToken }
      }
    );
  }

  getMovieDetails(movieId: string)
  {
    return this.httpClient.get<Movie>
    (environment.baseURL+this.getMovieDetailsByMovieIdURL+movieId,
      {
        params: { 'api_key': environment.apiToken }
      }
    );
  }

}
